// Pass 0 Analysis — Rec.709 luminance conversion, byte-exact with
// the legacy cs_analysis entry point. Output channels R=G=B=luma,
// A=1 so downstream samplers reading .r get the luma scalar.

struct U { _pad0: f32, };
@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var source: texture_2d<f32>;
@group(0) @binding(2) var samp: sampler;
@group(0) @binding(3) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) id: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if id.x >= dims.x || id.y >= dims.y { return; }
    _ = u._pad0;
    let uv = (vec2<f32>(id.xy) + 0.5) / vec2<f32>(dims);
    let rgb = textureSampleLevel(source, samp, uv, 0.0).rgb;
    let l = dot(rgb, vec3<f32>(0.2126, 0.7152, 0.0722));
    textureStore(output_tex, vec2<i32>(id.xy), vec4<f32>(l, l, l, 1.0));
}

// Identity-UV writer for the mesh_coord persistent state on first
// frame and after scene cuts. Mirrors PASS_INIT_MESH_COORD from
// fx_wireframe_depth_compute.wgsl byte-exact:
//   RG = (u, v), B = 1.0 (full trust), A = encode_cooldown(0.0) = 0.55.
// The 0.55 alpha decodes back to 0 cooldown via decode_cooldown so
// downstream FlowAdvectCoord sees a freshly-recovered tile.

struct U { _pad0: f32, };
@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) id: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if id.x >= dims.x || id.y >= dims.y { return; }
    _ = u._pad0;
    let uv = (vec2<f32>(id.xy) + 0.5) / vec2<f32>(dims);
    textureStore(output_tex, vec2<i32>(id.xy), vec4<f32>(uv, 1.0, 0.55));
}

// Pass 4 DnnDepthPost, extracted byte-exact from
// fx_wireframe_depth_compute.wgsl. Mixes the current DNN depth with
// the previous frame's smoothed depth weighted by temporal_smooth
// * 0.85 (the 0.85 constant is preserved literally).

struct U {
    temporal_smooth: f32,
    _pad0: f32,
    _pad1: f32,
    _pad2: f32,
};
@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var current_depth: texture_2d<f32>;
@group(0) @binding(2) var prev_depth: texture_2d<f32>;
@group(0) @binding(3) var samp: sampler;
@group(0) @binding(4) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) id: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if id.x >= u32(dims.x) || id.y >= u32(dims.y) { return; }
    let uv = (vec2<f32>(id.xy) + 0.5) / vec2<f32>(dims);
    let depth_current = textureSampleLevel(current_depth, samp, uv, 0.0).r;
    let depth_previous = textureSampleLevel(prev_depth, samp, uv, 0.0).r;
    let depth_smoothed = mix(depth_current, depth_previous, u.temporal_smooth * 0.85);
    let depth_value = clamp(depth_smoothed, 0.0, 1.0);
    textureStore(output_tex, vec2<i32>(id.xy), vec4<f32>(depth_value, depth_value, depth_value, 1.0));
}

// Pass 10 SemanticMask extracted byte-exact from
// fx_wireframe_depth_compute.wgsl. Heuristic body / face / boundary
// detection from luma gradient + depth + flow confidence — NOT a
// DNN, fast per-pixel evidence fusion. Output channels:
//   R = body, G = face, B = boundary, A = 1.
// All thresholds (0.14, 0.64, 0.05, 0.92, 0.32, 0.98, 0.10, 0.70,
// 0.07, 0.28) preserved literally.

struct U {
    texel_x: f32,
    texel_y: f32,
    _pad0: f32,
    _pad1: f32,
};
@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var analysis_tex: texture_2d<f32>;
@group(0) @binding(2) var depth_tex: texture_2d<f32>;
@group(0) @binding(3) var flow_tex: texture_2d<f32>;
@group(0) @binding(4) var samp: sampler;
@group(0) @binding(5) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) id: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if id.x >= u32(dims.x) || id.y >= u32(dims.y) { return; }
    let uv = (vec2<f32>(id.xy) + 0.5) / vec2<f32>(dims);
    let texel = vec2<f32>(u.texel_x, u.texel_y);

    let lum = textureSampleLevel(analysis_tex, samp, uv, 0.0).r;
    let depth_val = textureSampleLevel(depth_tex, samp, uv, 0.0).r;
    let flow = textureSampleLevel(flow_tex, samp, uv, 0.0);
    let flow_conf = clamp(flow.b * flow.a, 0.0, 1.0);

    let l_l = textureSampleLevel(analysis_tex, samp, uv - vec2<f32>(texel.x, 0.0), 0.0).r;
    let l_r = textureSampleLevel(analysis_tex, samp, uv + vec2<f32>(texel.x, 0.0), 0.0).r;
    let l_b = textureSampleLevel(analysis_tex, samp, uv - vec2<f32>(0.0, texel.y), 0.0).r;
    let l_t = textureSampleLevel(analysis_tex, samp, uv + vec2<f32>(0.0, texel.y), 0.0).r;
    let grad = sqrt((l_r - l_l) * (l_r - l_l) + (l_t - l_b) * (l_t - l_b));

    var body = smoothstep(0.14, 0.64, flow_conf * 0.92 + (1.0 - depth_val) * 0.16 + grad * 0.20);
    body = body * smoothstep(0.05, 0.92, 1.0 - abs(lum - 0.5) * 1.4);

    let p_val = (uv - vec2<f32>(0.5)) * vec2<f32>(1.20, 1.55);
    let center_bias = 1.0 - smoothstep(0.32, 0.98, length(p_val));
    let face = body * center_bias * smoothstep(0.10, 0.70, (1.0 - depth_val) * 0.35 + flow_conf * 0.65);

    var boundary_val = smoothstep(0.07, 0.28, grad) * body;
    boundary_val = clamp(boundary_val * (0.6 + (1.0 - face) * 0.4), 0.0, 1.0);

    textureStore(output_tex, vec2<i32>(id.xy), vec4<f32>(clamp(body, 0.0, 1.0), clamp(face, 0.0, 1.0), clamp(boundary_val, 0.0, 1.0), 1.0));
}
